import './Expenses.css';
import ExpenseItem from './ExpenseItem';
import Card from '../UI/Card';


function Expenses(props){
    const expenseList = props.expenseList;
    return (
        <div>
            <Card className = 'expenses'>
                <ExpenseItem date = {expenseList.item1.date} title = {expenseList.item1.title} amount = {expenseList.item1.amount}></ExpenseItem>
                <ExpenseItem date = {expenseList.item2.date} title = {expenseList.item2.title} amount = {expenseList.item2.amount}></ExpenseItem>
                <ExpenseItem date = {expenseList.item3.date} title = {expenseList.item3.title} amount = {expenseList.item3.amount}></ExpenseItem>
            </Card>
        </div>
    )
}
export default Expenses;
